prompts.code:
System.out.println("Search by: 1. Name  2. Price range  3. Department");
int option = scanner.nextInt(); scanner.nextLine();
List<Product> results = new ArrayList<>();
if (option == 1) {
    System.out.print("Name contains: ");
    String term = scanner.nextLine().toLowerCase();
    for (Product p : products) {
        if (p.getName().toLowerCase().contains(term)) results.add(p);
    }
} else if (option == 2) {
    System.out.print("Min price: "); double min = scanner.nextDouble();
    System.out.print("Max price: "); double max = scanner.nextDouble();
    for (Product p : products) {
        if (p.getPrice() >= min && p.getPrice() <= max) results.add(p);
    }
}
results.forEach(System.out::println);

